<?php
namespace App\Http\Controllers\Admin\Content;use App\Domain\Shops\Admin\ShopAdminReadService;use App\Domain\Shops\Admin\ShopAdminService;use App\Domain\Shops\ShopPurchaseRate;use App\Http\Controllers\Controller;use App\Http\Requests\Admin\Content\ShopRequest;use App\Models\Shop;use InvalidArgumentException;
final class ShopController extends Controller{public function index(ShopAdminReadService $read){return view('admin.content.shops.index',['shops'=>$read->listing()]);}public function create(ShopAdminReadService $read,ShopPurchaseRate $rates){return view('admin.content.shops.form',$this->form($read,$rates,new Shop()));}public function store(ShopRequest $request,ShopAdminService $service){return$this->save($request,$service,null,'Shop creada correctamente.');}public function edit(Shop $shop,ShopAdminReadService $read,ShopPurchaseRate $rates){return view('admin.content.shops.form',$this->form($read,$rates,$shop));}public function update(ShopRequest $request,Shop $shop,ShopAdminService $service){return$this->save($request,$service,$shop,'Shop actualizada correctamente.');}public function activate(Shop $shop,ShopAdminService $service){$service->activate($shop);return back()->with('status','Shop activada correctamente.');}public function deactivate(Shop $shop,ShopAdminService $service){$service->deactivate($shop);return back()->with('status','Shop desactivada correctamente.');}public function hide(Shop $shop,ShopAdminService $service){$service->hide($shop);return back()->with('status','Shop ocultada correctamente.');}private function form($read,$rates,Shop $shop){$data=$read->form($shop);$data['purchase_rate_percent']=$rates->toPercentage($shop->exists?(int)$shop->purchase_rate_basis_points:10000);return$data;}private function save($request,$service,$shop,$message){try{$saved=$service->save($request->validated(),$shop);return redirect()->route('admin.content.shops.edit',$saved)->with('status',$message);}catch(InvalidArgumentException $e){return back()->withInput()->withErrors(['content'=>$e->getMessage()]);}}}
